INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VTX_2023_consolidated', 'VTX', 2023, 'consolidated', 'Ernst & Young Vietnam Limited', 'unqualified', 0, NULL),
('VTX_2025_consolidated', 'VTX', 2025, 'consolidated', 'Ernst & Young Việt Nam', 'unqualified', 1, 'Công ty đã phát sinh lỗ thuần cho năm tài chính kết thúc ngày 31 tháng 12 năm 2025 với số tiền là 35.336.974.391 VND và tại ngày này, lỗ lũy kế của Công ty là 180.674.309.657 VND. Tại ngày 31 tháng 12 năm 2025, nợ ngắn hạn của Công ty cũng đã vượt quá tài sản ngắn hạn với số tiền là 62.937.115.394 VND. Do đó, khả năng Công ty tiếp tục duy trì hoạt động kinh doanh phụ thuộc vào khả năng hoạt động kinh doanh có lợi nhuận trong tương lai và tiếp tục nhận được sự hỗ trợ tài chính từ công ty mẹ.'),
('VTX_2024_consolidated', 'VTX', 2024, 'consolidated', 'Ernst & Young Việt Nam', 'unqualified', 1, 'Công ty phát sinh lỗ thuần 104,683,866,698 VND và lỗ lũy kế 145,337,335,266 VND, nợ ngắn hạn vượt quá tài sản ngắn hạn 40,030,302,968 VND, cho thấy nghi ngờ về khả năng hoạt động liên tục. Công ty phụ thuộc vào sự hỗ trợ tài chính từ công ty mẹ là Công ty Cổ phần Kho Vận Miền Nam.'),
('VTX_2022_consolidated', 'VTX', 2022, 'consolidated', 'Ernst & Young Việt Nam', 'unqualified', 0, NULL),
