INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VTSS_2021_consolidated', 'VTSS', 2021, 'consolidated', 'Chi nhánh Công ty TNHH Kiểm toán - Tư vấn Đất Việt tại Hà Nội', 'unqualified', 0, NULL),
('VTSS_2020_consolidated', 'VTSS', 2020, 'consolidated', 'Công ty TNHH Hăng Kiểm toán AASC', 'unqualified', 1, 'Lỗ lũy kế âm 43,3 tỷ đồng và hoạt động không tăng trưởng do cạnh tranh từ các công ty chứng khoán lớn, dẫn đến nghi ngờ trọng yếu về khả năng hoạt động liên tục.'),
('VTSS_2019_consolidated', 'VTSS', 2019, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Công ty đang lỗ lũy kế âm 42,13 tỷ đồng (tương đương 30,53% vốn góp của chủ sở hữu). Hoạt động kinh doanh trong năm 2019 không có sự tăng trưởng đáng kể do cạnh tranh từ các công ty chứng khoán lớn. Tuy nhiên, Ban Điều hành đang có định hướng phát triển mới: đẩy mạnh môi giới, xin cấp phép tự doanh và cho vay ký quỹ.'),
('VTSC_2025_consolidated', 'VTSC', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 0, NULL),
('VTSS_2015_consolidated', 'VTSS', 2015, 'consolidated', 'AASC', 'unqualified', 0, NULL),
('VTSC_2023_consolidated', 'VTSC', 2023, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 0, NULL),
('VTSS_2017_consolidated', 'VTSS', 2017, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VTSC_2024_consolidated', 'VTSC', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C (Baker Tilly A&C)', 'unqualified', 0, NULL),
('VTSC_2020_consolidated', 'VTSC', 2020, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'unqualified', 0, NULL),
('VTSC_2019_consolidated', 'VTSC', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C (Baker Tilly A&C)', 'unqualified', 0, NULL),
('VTSC_2017_consolidated', 'VTSC', 2017, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C (A&C Auditing and Consulting Co., Ltd.)', 'unqualified', 0, NULL),
('VTSC_2021_consolidated', 'VTSC', 2021, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 0, NULL),
('VTSC_2018_consolidated', 'VTSC', 2018, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'unqualified', 0, NULL),
('VTSC_2016_consolidated', 'VTSC', 2016, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'unqualified', 0, NULL),
('VTSC_2015_consolidated', 'VTSC', 2015, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 0, NULL),
('VTS_2024_consolidated', 'VTS', 2024, 'consolidated', 'AASC', 'unqualified', 1, 'Đến thời điểm 31/12/2024, lỗ lũy kế của Công ty là 36,59 tỷ VND, tương ứng 183% vốn góp của chủ sở hữu. Công ty đang tạm dùng hoạt động sản xuất tại Nhà máy Từ Sơn và đang trong quá trình thanh lý tài sản tại Nhà máy Hải Dương do đất bị thu hồi. Những sự kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VTS_2025_consolidated', 'VTS', 2025, 'consolidated', 'Công ty TNHH Hằng Kiểm toán AASC', 'unqualified', 1, 'Tại ngày 31/12/2025, lỗ lũy kế của Công ty là 35,86 tỷ VND, tương ứng 179% vốn góp của chủ sở hữu, dẫn đến nghi ngờ về khả năng hoạt động liên tục.'),
('VTS_2023_consolidated', 'VTS', 2023, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Một phần diện tích đất thuê tại Nhà máy Hải Dương đã hết thời hạn thuê và đang trong quá trình chuẩn bị bàn giao mặt bằng theo Quyết định số 2832/QĐ-UBND ngày 28/09/2021. Công ty đang tìm kiếm đối tác để thanh lý nguyên vật liệu, tài sản không có nhu cầu sử dụng tại nhà máy này.'),
('VTS_2019_consolidated', 'VTS', 2019, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VTS_2021_consolidated', 'VTS', 2021, 'consolidated', 'Công ty TNHH Hăng kiểm toán AASC', 'unqualified', 0, NULL);
