INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VTQ_2025_consolidated', 'VTQ', 2025, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế (iCPA)', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2025, Nợ ngắn hạn đã vượt quá Tài sản ngắn hạn của Công ty với số tiền là 37.191.542.190 đồng (tại ngày 01/01/2025 là 34.566.641.101 đồng). Lỗ lũy kế của Công ty đến ngày 31/12/2025 là 45.079.710.124 đồng (lỗ lũy kế đến ngày 01/01/2025 là 51.434.030.126 đồng). Điều này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VTQ_2024_consolidated', 'VTQ', 2024, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế (iCPA)', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2024, Nợ ngắn hạn đã vượt quá Tài sản ngắn hạn của Công ty với số tiền là 34.566.641.101 đồng (tại ngày 01/01/2024 là 47.119.868.938 đồng). Lỗ lũy kế của Công ty đến ngày 31/12/2024 là 51.434.030.126 đồng (lỗ lũy kế đến ngày 01/01/2024 là 55.401.699.363 đồng). Điều này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VTQ_2022_consolidated', 'VTQ', 2022, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2022, các khoản nợ ngắn hạn của Công ty đã vượt quá tài sản ngắn hạn là 37.852.147.239 đồng. Ngoài ra, lưu chuyển tiền thuần từ hoạt động kinh doanh năm 2022 bị âm 5.797.407.644 đồng.'),
('VTQ_2023_consolidated', 'VTQ', 2023, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế (iCPA)', 'qualified', 1, 'Tại ngày 31 tháng 12 năm 2023, Nợ ngắn hạn đã vượt quá Tài sản ngắn hạn của Công ty với số tiền là 47.119.868.938 đồng. Hoạt động kinh doanh năm 2023 của Công ty đang bị lỗ với số tiền là 41.428.348.283 đồng, dẫn đến lỗ lũy kế là 53.519.401.139 đồng.'),
('VTQ_2021_consolidated', 'VTQ', 2021, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế', 'unqualified', 1, 'Tổng nợ ngắn hạn vượt quá tài sản ngắn hạn 30.450.639.298 đồng và lưu chuyển tiền thuần từ hoạt động kinh doanh âm 21.406.331.524 đồng, cho thấy nghi ngờ về khả năng hoạt động liên tục.'),
('VTQ_2018_consolidated', 'VTQ', 2018, 'consolidated', 'PKF Việt Nam', 'qualified', 1, 'Tài sản ngắn hạn (42,399,569,716 VNĐ) thấp hơn nợ ngắn hạn (130,298,140,873 VNĐ) với số tiền chênh lệch là 87,898,571,157 VNĐ. Lưu chuyển tiền thuần từ hoạt động kinh doanh bị âm 20,334,875,794 VNĐ.'),
('VTQ_2019_consolidated', 'VTQ', 2019, 'consolidated', 'PKF Việt Nam', 'qualified', 1, 'Tài sản ngắn hạn là 22.623.539.897 đồng, nợ ngắn hạn là 85.257.100.305 đồng, nợ ngắn hạn vượt tài sản ngắn hạn 62.633.560.408 đồng. Lưu chuyển tiền thuần từ hoạt động kinh doanh âm 9.190.770.386 đồng.'),
('VTQ_2020_consolidated', 'VTQ', 2020, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế (iCPA)', 'qualified', 1, 'Tài sản ngắn hạn là 33.872.906.450 đồng, nợ ngắn hạn là 78.361.081.378 đồng, nợ ngắn hạn vượt tài sản ngắn hạn 44.488.174.928 đồng. Lưu chuyển tiền thuần từ hoạt động kinh doanh bị âm 10.515.730.549 đồng. Quỹ khen thưởng phúc lợi đang bị âm 3.398.849.681 đồng. Hội đồng Quản trị và Ban Giám đốc đã xây dựng phương án kinh doanh để đảm bảo khả năng thanh toán các khoản nợ đến hạn trong vòng 01 năm tới.'),
